import { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Type, Image as ImageIcon, Sparkles, Shapes, 
  Layers, Palette, Trash2, Move, LayoutGrid,
  Search, Plus, Crown, MousePointer2, 
  RotateCw, FlipHorizontal, ChevronRight, 
  ChevronLeft, ShoppingCart, Check, Info,
  Maximize2, Eye, Download, Bold, Italic, 
  AlignLeft, AlignCenter, AlignRight, Smartphone
} from 'lucide-react';
import { useCart } from '../context/AppContext';

// --- CONFIGURATION DES ASSETS (Simulé - Alimenté par l'Admin) ---
const ASSET_LIBRARY = {
  stickers: [
    { id: 's1', url: 'https://cdn-icons-png.flaticon.com/512/2592/2592323.png', premium: false },
    { id: 's2', url: 'https://cdn-icons-png.flaticon.com/512/1828/1828884.png', premium: true },
    { id: 's3', url: 'https://cdn-icons-png.flaticon.com/512/929/929424.png', premium: false },
  ],
  illustrations: [
    { id: 'i1', url: 'https://cdn-icons-png.flaticon.com/512/6122/6122557.png', premium: true },
    { id: 'i2', url: 'https://cdn-icons-png.flaticon.com/512/4359/4359654.png', premium: false },
  ],
  shapes: [
    { id: 'sh1', type: 'circle', color: '#1A1A1A' },
    { id: 'sh2', type: 'square', color: '#017BFE' },
  ]
};

const PRODUCTS = [
  { id: 'tshirt', label: 'T-Shirt Premium', price: 10000, sizes: ['S', 'M', 'L', 'XL'] },
  { id: 'hoodie', label: 'Hoodie Oversize', price: 18000, sizes: ['M', 'L', 'XL'] },
];

export default function Personnalisation() {
  const { addToCart } = useCart();
  const [activeTab, setActiveTab] = useState('stickers');
  const [selectedProduct, setSelectedProduct] = useState(PRODUCTS[0]);
  const [selectedSize, setSelectedSize] = useState('M');
  const [view, setView] = useState('face'); // face | back
  const [selectedElement, setSelectedElement] = useState(null);
  const [added, setAdded] = useState(false);

  // Styles partagés (Style Printed)
  const cardStyle = {
    background: 'white',
    borderRadius: 24,
    border: '1px solid #F1F5F9',
    boxShadow: '0 10px 30px rgba(0,0,0,0.02)',
    padding: 24
  };

  const sidebarTabs = [
    { id: 'stickers', icon: Sparkles, label: 'Stickers' },
    { id: 'illustrations', icon: LayoutGrid, label: 'Illustrations' },
    { id: 'typography', icon: Type, label: 'Texte' },
    { id: 'shapes', icon: Shapes, label: 'Formes' },
    { id: 'uploads', icon: ImageIcon, label: 'Mes Photos' },
  ];

  return (
    <div style={{ minHeight: '100vh', background: '#F8FAFC', padding: '120px 40px 40px' }}>
      <div style={{ maxWidth: 1400, margin: '0 auto', display: 'grid', gridTemplateColumns: '380px 1fr 320px', gap: 32, height: 'calc(100vh - 160px)' }}>

        {/* --- PANNEAU GAUCHE : BIBLIOTHÈQUE --- */}
        <div style={{ ...cardStyle, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          <div style={{ display: 'flex', gap: 8, marginBottom: 24, paddingBottom: 16, borderBottom: '1px solid #F1F5F9', overflowX: 'auto' }}>
            {sidebarTabs.map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                style={{
                  flexShrink: 0, padding: '10px 16px', borderRadius: 14, border: 'none',
                  background: activeTab === tab.id ? '#017BFE' : '#F8FAFC',
                  color: activeTab === tab.id ? 'white' : '#64748B',
                  cursor: 'pointer', transition: '0.2s', display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, fontSize: 13
                }}
              >
                <tab.icon size={16} /> {tab.label}
              </button>
            ))}
          </div>

          <div style={{ position: 'relative', marginBottom: 20 }}>
            <Search size={16} color="#94A3B8" style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)' }} />
            <input 
              placeholder="Rechercher..." 
              style={{ width: '100%', padding: '14px 14px 14px 42px', borderRadius: 16, border: '1px solid #E2E8F0', outline: 'none', fontSize: 14 }}
            />
          </div>

          <div style={{ flex: 1, overflowY: 'auto', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, paddingRight: 4 }}>
            {/* Simulation des items de la bibliothèque */}
            {(activeTab === 'stickers' ? ASSET_LIBRARY.stickers : activeTab === 'illustrations' ? ASSET_LIBRARY.illustrations : []).map((item) => (
              <div 
                key={item.id}
                style={{ 
                  aspectRatio: '1', background: '#F8FAFC', borderRadius: 20, cursor: 'pointer', 
                  display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', border: '2px solid transparent', transition: '0.2s' 
                }}
                onMouseEnter={e => e.currentTarget.style.borderColor = '#017BFE'}
                onMouseLeave={e => e.currentTarget.style.borderColor = 'transparent'}
              >
                <img src={item.url} style={{ width: '70%', objectFit: 'contain' }} alt="asset" />
                {item.premium && <Crown size={14} style={{ position: 'absolute', top: 12, right: 12, color: '#E6B95E' }} />}
              </div>
            ))}

            {activeTab === 'typography' && (
              <div style={{ gridColumn: '1 / span 2', display: 'flex', flexDirection: 'column', gap: 10 }}>
                {['Titre Impact', 'Script Élégant', 'Moderne Sans', 'Vintage Sport'].map(font => (
                  <button key={font} style={{ width: '100%', padding: 16, borderRadius: 16, border: '1px solid #E2E8F0', background: 'white', textAlign: 'left', cursor: 'pointer', fontWeight: 700 }}>
                    {font}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* --- ZONE CENTRALE : CANVAS --- */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
          {/* Barre d'outils contextuelle (Uniquement si sélection) */}
          <div style={{ 
            height: 60, background: 'white', borderRadius: 20, padding: '0 20px', 
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 24,
            boxShadow: '0 10px 25px rgba(0,0,0,0.03)', border: '1px solid #F1F5F9',
            visibility: selectedElement ? 'visible' : 'hidden' 
          }}>
            <button style={{ border: 'none', background: 'none', color: '#64748B', cursor: 'pointer' }}><RotateCw size={20} /></button>
            <button style={{ border: 'none', background: 'none', color: '#64748B', cursor: 'pointer' }}><FlipHorizontal size={20} /></button>
            <div style={{ width: 1, height: 24, background: '#E2E8F0' }} />
            <button style={{ border: 'none', background: 'none', color: '#64748B', cursor: 'pointer' }}><Layers size={20} /></button>
            <button style={{ border: 'none', background: 'none', color: '#EF4444', cursor: 'pointer' }}><Trash2 size={20} /></button>
          </div>

          <div style={{ flex: 1, ...cardStyle, position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
            {/* Sélecteur de vue flottant */}
            <div style={{ position: 'absolute', bottom: 30, left: '50%', transform: 'translateX(-50%)', background: '#1A1A1A', padding: '6px', borderRadius: 16, display: 'flex', gap: 4, zIndex: 10 }}>
              <button onClick={() => setView('face')} style={{ border: 'none', padding: '10px 24px', borderRadius: 12, fontSize: 12, fontWeight: 800, cursor: 'pointer', background: view === 'face' ? '#017BFE' : 'transparent', color: 'white' }}>FACE</button>
              <button onClick={() => setView('back')} style={{ border: 'none', padding: '10px 24px', borderRadius: 12, fontSize: 12, fontWeight: 800, cursor: 'pointer', background: view === 'back' ? '#017BFE' : 'transparent', color: 'white' }}>DOS</button>
            </div>

            {/* Mockup Container */}
            <div style={{ width: '85%', height: '85%', position: 'relative' }}>
              <img 
                src={view === 'face' ? "/mockups/tshirt-front.png" : "/mockups/tshirt-back.png"} 
                style={{ width: '100%', height: '100%', objectFit: 'contain' }}
                alt="Product"
              />
              {/* Overlay Zone d'impression */}
              <div style={{ 
                position: 'absolute', top: '22%', left: '28%', width: '44%', height: '52%', 
                border: '1px dashed rgba(1, 123, 254, 0.2)', borderRadius: 4,
                display: 'flex', alignItems: 'center', justifyContent: 'center'
              }}>
                <p style={{ color: '#017BFE', fontSize: 10, fontWeight: 700, opacity: 0.4, position: 'absolute', bottom: -24 }}>ZONE D'IMPRESSION</p>
              </div>
            </div>
          </div>
        </div>

        {/* --- PANNEAU DROIT : CONFIGURATION --- */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
          {/* Choix Produit */}
          <div style={cardStyle}>
            <h3 style={{ fontSize: 16, fontWeight: 900, marginBottom: 20, display: 'flex', alignItems: 'center', gap: 10 }}>
               Configuration
            </h3>

            <div style={{ marginBottom: 24 }}>
              <p style={{ fontSize: 12, fontWeight: 800, color: '#94A3B8', marginBottom: 12, textTransform: 'uppercase' }}>Produit</p>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {PRODUCTS.map(p => (
                  <button 
                    key={p.id}
                    onClick={() => setSelectedProduct(p)}
                    style={{ 
                      padding: 14, borderRadius: 16, border: '1px solid', 
                      borderColor: selectedProduct.id === p.id ? '#017BFE' : '#E2E8F0',
                      background: selectedProduct.id === p.id ? '#F0F7FF' : 'white',
                      textAlign: 'left', cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center'
                    }}
                  >
                    <span style={{ fontWeight: 700, fontSize: 14 }}>{p.label}</span>
                    {selectedProduct.id === p.id && <Check size={16} color="#017BFE" />}
                  </button>
                ))}
              </div>
            </div>

            <div style={{ marginBottom: 24 }}>
              <p style={{ fontSize: 12, fontWeight: 800, color: '#94A3B8', marginBottom: 12, textTransform: 'uppercase' }}>Taille</p>
              <div style={{ display: 'flex', gap: 8 }}>
                {selectedProduct.sizes.map(size => (
                  <button 
                    key={size}
                    onClick={() => setSelectedSize(size)}
                    style={{ 
                      flex: 1, height: 44, borderRadius: 12, border: '1px solid',
                      borderColor: selectedSize === size ? '#1A1A1A' : '#E2E8F0',
                      background: selectedSize === size ? '#1A1A1A' : 'white',
                      color: selectedSize === size ? 'white' : '#1A1A1A',
                      fontWeight: 700, cursor: 'pointer'
                    }}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>

            <div style={{ background: '#F8FAFC', padding: 20, borderRadius: 20, marginBottom: 24 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                <span style={{ fontSize: 14, fontWeight: 600, color: '#64748B' }}>Prix total</span>
                <span style={{ fontSize: 18, fontWeight: 900, color: '#017BFE' }}>{selectedProduct.price.toLocaleString()} F</span>
              </div>
              <p style={{ fontSize: 11, color: '#94A3B8', fontWeight: 500 }}>TVA et impression de base incluse</p>
            </div>

            <button 
              onClick={() => { setAdded(true); setTimeout(() => setAdded(false), 2000); }}
              style={{ 
                width: '100%', padding: '16px', borderRadius: 18, border: 'none',
                background: added ? '#02AB84' : '#017BFE', color: 'white',
                fontWeight: 800, fontSize: 15, cursor: 'pointer', 
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
                boxShadow: '0 10px 20px rgba(1,123,254,0.15)'
              }}
            >
              {added ? <Check size={20} /> : <ShoppingCart size={20} />}
              {added ? 'Ajouté au panier' : 'Commander'}
            </button>
          </div>

          {/* Tips / Aide */}
          <div style={{ ...cardStyle, background: '#F0F7FF', borderColor: '#D0E7FF' }}>
            <h4 style={{ fontSize: 13, fontWeight: 800, color: '#017BFE', marginBottom: 10, display: 'flex', alignItems: 'center', gap: 8 }}>
              <Info size={16} /> Astuces
            </h4>
            <ul style={{ padding: 0, margin: 0, listStyle: 'none', display: 'flex', flexDirection: 'column', gap: 8 }}>
              {[
                'Utilisez des images PNG pour un meilleur rendu',
                'Le prix varie selon le nombre de faces imprimées',
                'Livraison gratuite dès 25.000 F'
              ].map((tip, i) => (
                <li key={i} style={{ fontSize: 11, color: '#4B7299', fontWeight: 600, display: 'flex', gap: 6 }}>
                  • {tip}
                </li>
              ))}
            </ul>
          </div>
        </div>

      </div>
    </div>
  );
}
